src/util.classify.code:
export function classify<T extends { name: string }>(items: T[]): Record<string, T[]> {
  function keyOf(item: T): string {
    return item.name.charAt(0);
  }
  const out: Record<string, T[]> = {};
  for (const item of items) {
    const k = keyOf(item);
    (out[k] ??= []).push(item);
  }
  return out;
}

